mapper.select:
SELECT COUNT(*) FROM (
    SELECT user_id FROM post 
    WHERE status = 1
    GROUP BY user_id 
    HAVING COUNT(*) >= #{minPosts}
) AS creators

SELECT COUNT(*) FROM (
    SELECT user_id FROM comment 
    GROUP BY user_id 
    HAVING COUNT(*) >= #{minComments}
) AS interactors

SELECT COUNT(DISTINCT user_id) FROM (
    SELECT user_id FROM post WHERE DATE(create_time) BETWEEN #{startDate} AND #{endDate}
    UNION
    SELECT user_id FROM comment WHERE DATE(create_time) BETWEEN #{startDate} AND #{endDate}
) AS active_users
